# OPTIMIZED: Use as_dict() with appropriate options
def get_item_defaults(item, company):
    out = {}
    for d in item.item_defaults:
        if d.company == company:
            # FIX: Use as_dict() which is already a copy
            # no_private_properties=True excludes internal fields
            row = d.as_dict(no_private_properties=True)
            row.pop("name")
            out.update(row)
    return out
